package javaday10;

public class nestediselse {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		if(1==1)
		{
			if(2==1)
			{
			    System.out.println("ABC");
			}
			else
			{
				System.out.println("123");
			}
		}
		else
		{
			if(2==2)
			{
			    System.out.println("XYZ");
			}
		}

	}

}
